package com.taskflow.entity;

import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.EnumSource;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Pure unit tests for TaskStatus enum.
 * No Spring context needed — tests enum values and state machine logic.
 */
class TaskStatusTest {

    // ── Contract: enum values ──────────────────────────────────────────

    @Test
    @DisplayName("TaskStatus has exactly 4 values: TODO, IN_PROGRESS, DONE, CLOSED")
    void shouldHaveExactlyFourValues() {
        TaskStatus[] values = TaskStatus.values();
        assertEquals(4, values.length);
        assertNotNull(TaskStatus.valueOf("TODO"));
        assertNotNull(TaskStatus.valueOf("IN_PROGRESS"));
        assertNotNull(TaskStatus.valueOf("DONE"));
        assertNotNull(TaskStatus.valueOf("CLOSED"));
    }

    // ── getAllowedTransitions ───────────────────────────────────────────

    @Nested
    @DisplayName("getAllowedTransitions()")
    class GetAllowedTransitionsTests {

        @Test
        @DisplayName("TODO -> [IN_PROGRESS]")
        void todoAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.TODO.getAllowedTransitions();
            assertEquals(1, allowed.size());
            assertTrue(allowed.contains(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("IN_PROGRESS -> [TODO, DONE]")
        void inProgressAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.IN_PROGRESS.getAllowedTransitions();
            assertEquals(2, allowed.size());
            assertTrue(allowed.contains(TaskStatus.TODO));
            assertTrue(allowed.contains(TaskStatus.DONE));
        }

        @Test
        @DisplayName("DONE -> [CLOSED]")
        void doneAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.DONE.getAllowedTransitions();
            assertEquals(1, allowed.size());
            assertTrue(allowed.contains(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("CLOSED -> [] (empty, terminal state)")
        void closedAllowedTransitions() {
            List<TaskStatus> allowed = TaskStatus.CLOSED.getAllowedTransitions();
            assertNotNull(allowed);
            assertTrue(allowed.isEmpty());
        }
    }

    // ── canTransitionTo — valid transitions ────────────────────────────

    @Nested
    @DisplayName("canTransitionTo() — valid transitions")
    class ValidTransitionTests {

        @Test
        @DisplayName("TODO -> IN_PROGRESS = true")
        void todoToInProgress() {
            assertTrue(TaskStatus.TODO.canTransitionTo(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("IN_PROGRESS -> TODO = true")
        void inProgressToTodo() {
            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("IN_PROGRESS -> DONE = true")
        void inProgressToDone() {
            assertTrue(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.DONE));
        }

        @Test
        @DisplayName("DONE -> CLOSED = true")
        void doneToClosed() {
            assertTrue(TaskStatus.DONE.canTransitionTo(TaskStatus.CLOSED));
        }
    }

    // ── canTransitionTo — invalid transitions ──────────────────────────

    @Nested
    @DisplayName("canTransitionTo() — invalid transitions")
    class InvalidTransitionTests {

        @Test
        @DisplayName("TODO -> DONE = false")
        void todoToDone() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.DONE));
        }

        @Test
        @DisplayName("TODO -> CLOSED = false")
        void todoToClosed() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("TODO -> TODO = false (self-transition)")
        void todoToTodo() {
            assertFalse(TaskStatus.TODO.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("DONE -> TODO = false")
        void doneToTodo() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.TODO));
        }

        @Test
        @DisplayName("DONE -> IN_PROGRESS = false")
        void doneToInProgress() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.IN_PROGRESS));
        }

        @Test
        @DisplayName("DONE -> DONE = false (self-transition)")
        void doneToDone() {
            assertFalse(TaskStatus.DONE.canTransitionTo(TaskStatus.DONE));
        }

        @ParameterizedTest(name = "CLOSED -> {0} = false")
        @EnumSource(TaskStatus.class)
        @DisplayName("CLOSED -> anything = false (terminal state)")
        void closedToAnything(TaskStatus target) {
            assertFalse(TaskStatus.CLOSED.canTransitionTo(target));
        }

        @Test
        @DisplayName("IN_PROGRESS -> CLOSED = false")
        void inProgressToClosed() {
            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.CLOSED));
        }

        @Test
        @DisplayName("IN_PROGRESS -> IN_PROGRESS = false (self-transition)")
        void inProgressToInProgress() {
            assertFalse(TaskStatus.IN_PROGRESS.canTransitionTo(TaskStatus.IN_PROGRESS));
        }
    }

    // ── Edge cases ─────────────────────────────────────────────────────

    @Test
    @DisplayName("canTransitionTo with null target should not throw (return false or throw NPE)")
    void canTransitionToNull() {
        // Depending on implementation, this may throw NPE or return false.
        // We simply verify it does not return true.
        try {
            boolean result = TaskStatus.TODO.canTransitionTo(null);
            assertFalse(result);
        } catch (NullPointerException e) {
            // Also acceptable behavior
        }
    }
}

