package com.taskflow.repository;

import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Nested;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.autoconfigure.orm.jpa.DataJpaTest;
import org.springframework.boot.test.autoconfigure.orm.jpa.TestEntityManager;
import org.springframework.data.domain.Page;
import org.springframework.data.domain.PageRequest;
import org.springframework.data.domain.Pageable;

import java.util.List;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Integration tests for TaskRepository custom queries.
 * Uses @DataJpaTest with embedded H2.
 */
@DataJpaTest
class TaskRepositoryTest {

    @Autowired
    private TaskRepository taskRepository;

    @Autowired
    private TestEntityManager entityManager;

    private Task createTask(String title, Task.Priority priority, boolean deleted) {
        Task task = new Task();
        task.setTitle(title);
        task.setPriority(priority);
        task.setCreatedBy(1L);
        task.setDeleted(deleted);
        return entityManager.persistAndFlush(task);
    }

    private Task createTask(String title) {
        return createTask(title, Task.Priority.MEDIUM, false);
    }

    // ── Soft-delete exclusion ──────────────────────────────────────────

    @Nested
    @DisplayName("findByDeletedFalse — soft-delete exclusion")
    class SoftDeleteTests {

        @Test
        @DisplayName("Excludes soft-deleted tasks from results")
        void shouldExcludeSoftDeletedTasks() {
            createTask("Active Task 1");
            createTask("Active Task 2");
            createTask("Deleted Task", Task.Priority.MEDIUM, true);

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(2, result.getTotalElements());
            assertTrue(result.getContent().stream().noneMatch(Task::isDeleted));
        }

        @Test
        @DisplayName("Returns empty page when all tasks are soft-deleted")
        void shouldReturnEmptyWhenAllDeleted() {
            createTask("Deleted 1", Task.Priority.MEDIUM, true);
            createTask("Deleted 2", Task.Priority.HIGH, true);

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(0, result.getTotalElements());
            assertTrue(result.getContent().isEmpty());
        }

        @Test
        @DisplayName("Returns all tasks when none are soft-deleted")
        void shouldReturnAllWhenNoneDeleted() {
            createTask("Task 1");
            createTask("Task 2");
            createTask("Task 3");

            entityManager.clear();

            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 20));
            assertEquals(3, result.getTotalElements());
        }
    }

    // ── Keyword search ─────────────────────────────────────────────────

    @Nested
    @DisplayName("Keyword search — case-insensitive title matching")
    class KeywordSearchTests {

        @BeforeEach
        void setUp() {
            createTask("Build login page");
            createTask("Fix LOGIN bug");
            createTask("Design dashboard");
            createTask("Deleted login task", Task.Priority.MEDIUM, true);
            entityManager.clear();
        }

        @Test
        @DisplayName("Finds tasks with matching keyword (case-insensitive)")
        void shouldFindByCaseInsensitiveKeyword() {
            Pageable pageable = PageRequest.of(0, 20);

            // Search for "login" should match "Build login page" and "Fix LOGIN bug"
            // but NOT "Deleted login task" (soft-deleted)
            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "login", pageable);
            assertEquals(2, result.getTotalElements());
        }

        @Test
        @DisplayName("Returns empty when no title matches keyword")
        void shouldReturnEmptyWhenNoMatch() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "nonexistent", pageable);
            assertEquals(0, result.getTotalElements());
        }

        @Test
        @DisplayName("Keyword search excludes soft-deleted tasks")
        void keywordSearchShouldExcludeSoftDeleted() {
            Pageable pageable = PageRequest.of(0, 20);

            // "Deleted login task" is soft-deleted, so only 2 matches
            Page<Task> result = taskRepository.findByDeletedFalseAndTitleContainingIgnoreCase(
                    "login", pageable);
            result.getContent().forEach(task -> assertFalse(task.isDeleted()));
        }
    }

    // ── Priority filter ────────────────────────────────────────────────

    @Nested
    @DisplayName("Priority filter")
    class PriorityFilterTests {

        @BeforeEach
        void setUp() {
            createTask("High priority task", Task.Priority.HIGH, false);
            createTask("Medium priority task", Task.Priority.MEDIUM, false);
            createTask("Low priority task", Task.Priority.LOW, false);
            createTask("Another high task", Task.Priority.HIGH, false);
            createTask("Deleted high task", Task.Priority.HIGH, true);
            entityManager.clear();
        }

        @Test
        @DisplayName("Filters tasks by HIGH priority")
        void shouldFilterByHighPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.HIGH, pageable);
            assertEquals(2, result.getTotalElements());
            result.getContent().forEach(task ->
                    assertEquals(Task.Priority.HIGH, task.getPriority()));
        }

        @Test
        @DisplayName("Filters tasks by MEDIUM priority")
        void shouldFilterByMediumPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.MEDIUM, pageable);
            assertEquals(1, result.getTotalElements());
        }

        @Test
        @DisplayName("Filters tasks by LOW priority")
        void shouldFilterByLowPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.LOW, pageable);
            assertEquals(1, result.getTotalElements());
        }

        @Test
        @DisplayName("Priority filter excludes soft-deleted tasks")
        void priorityFilterShouldExcludeSoftDeleted() {
            Pageable pageable = PageRequest.of(0, 20);

            // 3 HIGH total, but 1 is soft-deleted
            Page<Task> result = taskRepository.findByDeletedFalseAndPriority(
                    Task.Priority.HIGH, pageable);
            assertEquals(2, result.getTotalElements());
            result.getContent().forEach(task -> assertFalse(task.isDeleted()));
        }
    }

    // ── Pagination ─────────────────────────────────────────────────────

    @Nested
    @DisplayName("Pagination")
    class PaginationTests {

        @BeforeEach
        void setUp() {
            for (int i = 1; i <= 15; i++) {
                createTask("Task " + i);
            }
            entityManager.clear();
        }

        @Test
        @DisplayName("Returns correct page size")
        void shouldReturnCorrectPageSize() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(0, 5));
            assertEquals(5, result.getContent().size());
            assertEquals(15, result.getTotalElements());
            assertEquals(3, result.getTotalPages());
        }

        @Test
        @DisplayName("Returns correct second page")
        void shouldReturnCorrectSecondPage() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(1, 5));
            assertEquals(5, result.getContent().size());
            assertEquals(1, result.getNumber());
        }

        @Test
        @DisplayName("Returns partial last page")
        void shouldReturnPartialLastPage() {
            Page<Task> result = taskRepository.findByDeletedFalse(PageRequest.of(2, 5));
            assertEquals(5, result.getContent().size());
        }
    }

    // ── Combined filters ───────────────────────────────────────────────

    @Nested
    @DisplayName("Combined keyword + priority filter")
    class CombinedFilterTests {

        @BeforeEach
        void setUp() {
            createTask("Build login page", Task.Priority.HIGH, false);
            createTask("Fix login bug", Task.Priority.MEDIUM, false);
            createTask("Design dashboard", Task.Priority.HIGH, false);
            entityManager.clear();
        }

        @Test
        @DisplayName("Filters by keyword AND priority together")
        void shouldFilterByKeywordAndPriority() {
            Pageable pageable = PageRequest.of(0, 20);

            Page<Task> result = taskRepository
                    .findByDeletedFalseAndTitleContainingIgnoreCaseAndPriority(
                            "login", Task.Priority.HIGH, pageable);
            assertEquals(1, result.getTotalElements());
            assertEquals("Build login page", result.getContent().get(0).getTitle());
        }
    }
}

