package com.taskflow.dto;

import com.taskflow.entity.Task;
import com.taskflow.entity.TaskStatus;
import org.junit.jupiter.api.DisplayName;
import org.junit.jupiter.api.Test;

import java.time.LocalDateTime;

import static org.junit.jupiter.api.Assertions.*;

/**
 * Contract tests for TaskResponse DTO.
 * Verifies field existence and types — no Spring context needed.
 */
class TaskResponseTest {

    // ── Contract: field types ──────────────────────────────────────────

    @Test
    @DisplayName("Contract: TaskResponse has all required fields with correct types")
    void contractFieldsExist() throws NoSuchMethodException {
        assertEquals(Long.class, TaskResponse.class.getMethod("getId").getReturnType());
        assertEquals(String.class, TaskResponse.class.getMethod("getTitle").getReturnType());
        assertEquals(String.class, TaskResponse.class.getMethod("getDescription").getReturnType());
        assertEquals(Task.Priority.class, TaskResponse.class.getMethod("getPriority").getReturnType());
        assertEquals(TaskStatus.class, TaskResponse.class.getMethod("getStatus").getReturnType());
        assertEquals(Long.class, TaskResponse.class.getMethod("getCreatedBy").getReturnType());
        assertEquals(LocalDateTime.class, TaskResponse.class.getMethod("getCreatedAt").getReturnType());
        assertEquals(LocalDateTime.class, TaskResponse.class.getMethod("getUpdatedAt").getReturnType());
    }

    // ── Field value round-trip ─────────────────────────────────────────

    @Test
    @DisplayName("TaskResponse getters/setters work correctly")
    void gettersAndSettersWork() {
        TaskResponse response = new TaskResponse();
        LocalDateTime now = LocalDateTime.now();

        response.setId(1L);
        response.setTitle("Test Task");
        response.setDescription("A description");
        response.setPriority(Task.Priority.HIGH);
        response.setStatus(TaskStatus.IN_PROGRESS);
        response.setCreatedBy(42L);
        response.setCreatedAt(now);
        response.setUpdatedAt(now);

        assertEquals(1L, response.getId());
        assertEquals("Test Task", response.getTitle());
        assertEquals("A description", response.getDescription());
        assertEquals(Task.Priority.HIGH, response.getPriority());
        assertEquals(TaskStatus.IN_PROGRESS, response.getStatus());
        assertEquals(42L, response.getCreatedBy());
        assertEquals(now, response.getCreatedAt());
        assertEquals(now, response.getUpdatedAt());
    }

    @Test
    @DisplayName("TaskResponse updatedAt can be null")
    void updatedAtCanBeNull() {
        TaskResponse response = new TaskResponse();
        response.setId(1L);
        response.setTitle("New Task");
        response.setUpdatedAt(null);

        assertNull(response.getUpdatedAt());
    }
}

