        @Override
        public List<TaskStatus> getAllowedTransitions() {
            return List.of(CLOSED);
        }
    },
    CLOSED {
        @Override
        public List<TaskStatus> getAllowedTransitions() {
            return List.of();
        }
    };

    public abstract List<TaskStatus> getAllowedTransitions();

    public boolean canTransitionTo(TaskStatus target) {
        return target != null && getAllowedTransitions().contains(target);
    }
}

